  border: none;
  color: rgba(0,0,0,1);
  font-weight: normal;
}

#article pre.custom code {
  display: -webkit-box;
  font-family: Consolas, Monaco, Menlo, monospace;
  font-size: 12px;
  -webkit-overflow-scrolling: touch;
}
#article pre.custom code span {
  line-height: 26px;
}

#article p code {
  word-wrap: break-word;
  font-family: Consolas, Monaco, Menlo, monospace;
  word-break: break-all;
}
#article li code {
  word-wrap: break-word;
  font-family: Consolas, Monaco, Menlo, monospace;
  word-break: break-all;
}

#article img {
  display: block;
  margin: 0 auto;
  max-width: 100%;
}
#article figure a {
  border: none;
}
#article figure a img {
  margin: 0px;
}
#article figure {
  display:flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}
/* 图片链接嵌套 */
#article figure a {
  display: flex;
  justify-content: center;
  align-items: center;
}

/* 图片链接嵌套，图片解释 */
#article figure a + figcaption {
  display: flex;
  justify-content: center;
  align-items: center;
  width: 100%;
  margin-top: -35px;
  background: rgba(0,0,0,0.7);
  color: white;
  line-height: 35px;
  z-index: 20;
}

#article .table-container {
  overflow-x: auto;
}
#article .table-container table {
  display: table;
  text-align: left;
}

#article .table-container table thead tr th {
  padding: 5px 10px;
}
/* 表格最小列宽4个汉字 */
#article .table-container table thead tr th:nth-of-type(n) {
  min-width: 85px;
}

#article .table-container table tbody {
  border: 0;
}
/* 表格最小列宽4个汉字 */
#article .table-container table tbody tr td:nth-of-type(n) {
  min-width:85px;
}
#article .table-container table tbody tr td {
  padding: 5px 10px;
}

#article .footnotes .footnote-num {
  display: inline;
  width: 10%; /*神奇，50px就不可以*/
  background: none;
  font-size: 80%;
  font-family: ptima-Regular, Optima, PingFangSC-light, PingFangTC-light, 'PingFang SC', Cambria, Cochin, Georgia, Times, 'Times New Roman', serif;
  padding-top: 2px;
}

#article .footnote-item p {
  display: inline;
  padding: 0px;
  margin: 0px;
  word-break: break-all;
  flex-basis: 0%;
  flex-grow: 1;
}

#article .block-equation {
  display:block;
  text-align: center;
  overflow: auto;
  display: block;
  -webkit-overflow-scrolling: touch;
}

#article .block-equation svg {
  max-width: 300% !important;
  -webkit-overflow-scrolling: touch;
}

#article .imageflow-layer1 {
  border: none;
  overflow: hidden;
}

#article .imageflow-layer2 {
  display: flex;
  flex-wrap: nowrap;
  overflow-x: scroll;
}

#article .imageflow-layer3 {
  flex: 0 0 100%;
}
#article .imageflow-img {
  display: inline-block;
}

#article .imageflow-caption {
  text-align: center;
  margin: 0px;
  padding: 0px;
}

#article .column {
  display: flex;
}

#article .column .column-left {
  text-align: center;
  padding-right: 5px;
  width: 50%;
}

#article .column .column-right {
  text-align: center;
  padding-left: 5px;
  width: 50%;
}

/*自定义样式，实时生效*/

/* 全局属性
 * 页边距 padding:30px;
 * 全文字体 font-family:ptima-Regular;
 * 英文换行 word-break:break-all;
 * PingFang在iOS上很好看;
 */
#article {
	font-family:"SF Pro SC","HanHei SC","SF Pro Text","Myriad Set Pro","SF Pro Icons","Apple Legacy Chevron","PingFang SC","Helvetica Neue","Helvetica","Arial",sans-serif;
  font-size:16px;
  padding:10px;

}

/* 段落，下方未标注标签参数均同此处
 * 上边距 margin-top:5px;
 * 下边距 margin-bottom:5px;
 * 行高 line-height:28px;
 * 词间距 word-spacing:0.1em;
 * 字间距 letter-spacing:0.1em;
 * 对齐-两端对齐 text-align:justify;
 * 颜色 color:rgba(0, 0, 0, 0.65);
 * 字体大小 font-size:16px;
 * 首行缩进 text-indent:2em;
 */
#article p {
  margin:5px 0px;
  line-height:1.75;
  letter-spacing:0.1em;
  font-size:16px;
  word-spacing:0.1em;
  /*text-align:justify;*/
  color:rgba(0, 0, 0, 0.85);
}



/* 一级标题，全文只有一个*/
#article h1 {
  text-align:center;
  line-height:100px;
  margin-top: 10px;
  margin-bottom: 10px;
  background-position: center top;
  background-repeat: no-repeat;
  background-size: 68px;

}
/* 一级标题内容 */
#article h1 .content {
  font-size: 22px;
  color: #E78E34;
  border-bottom:4px double #ffe3a3;
}

/* 一级标题修饰 请参考有实例的主题 */
#article h1:after {
}

/* 二级标题 */
#article h2 {
  text-align:center;
  display:block;
  background-position: center center;
  background-repeat: no-repeat;
  background-attachment: initial;
  background-origin: initial;
  background-clip: initial;
  background-size: 46px;
  margin-top: 30px;
  margin-bottom: 15px;
}

/* 二级标题内容 */
#article h2 .content {
  font-size:18px;
  color: #E78E34;;
  text-align:center;
  display: inline-block;
  height: 46px;
  line-height: 60px;
  background-position: left center;
  background-repeat: no-repeat;
  background-attachment: initial;
  background-origin: initial;
  background-clip: initial;

}
#article h2:before {
  content: "";
  background-image:   		    none;
    background-size: 100% 100%;
    background-repeat: no-repeat;
    display: inline-block;
    width: 28px;
    height: 28px;
    margin-bottom: -6px;
    margin-right: 0px;
  }

/* 二级标题修饰 请参考有实例的主题 */
