/* 无序列表整体样式
 * list-style-type: square|circle|disc;
 */
#article ul {
  font-size: 15px;
  margin-top: 8px;
  margin-bottom: 8px;
  padding-left: 20px;
  color: #E78E34;
}

/* 有序列表整体样式
 * list-style-type: upper-roman|lower-greek|lower-alpha;
 */
#article ol {
  font-size: 15px;
  margin-top: 8px;
  margin-bottom: 8px;
  padding-left: 20px;
  color: #E78E34;
}

/* 列表内容，不要设置li
 */
#article li section {
  letter-spacing:0.1em;
  word-spacing:0.1em;
  font-size:15px;
  color:rgb(0,0,0,0.65);
  font-weight: normal;
}

/* 引用
* 左边缘颜色 border-left-color:black;
* 背景色 background:gray;
*/
#article blockquote::before {

}

#article .multiquote-1 {
    background-color: #fff9f3;
    border-radius: 5px;
    border-left: 5px solid #E78E34;
    padding: 18px 21px;
}

#article blockquote p {
  margin-top:-15px;
  color: rgb(0,0,0,0.85)!important;
}

#article blockquote::after {

}

/* 链接 
 * border-bottom: 1px solid #009688;
 */
#article a {
  color:#E78E34;
  border-bottom:1px solid #E78E34;
  font-family:STHeitiSC-Light;
  font-weight:normal;
}

/* 加粗 */
#article strong {
  font-weight:bold;
  color:rgba(0, 0, 0, 0.85);
}

/* 斜体 */
#article em {
  color:rgba(0, 0, 0, 0.85);
  letter-spacing:0.1em;
}

/* 加粗斜体 */
#article em strong {
  font-style: normal;
  color:rgb(231, 142, 52);
  font-weight:bold;
  letter-spacing:0.01em;
}

/* 删除线 */
#article del {
}

/* 分隔线
 * 粗细、样式和颜色
 * border-top:1px solid #3e3e3e;
 */
#article hr {
  height:2px;
  padding:0;
  margin: 20px 0;
  border:none;
  border-top:medium solidid #333;
  text-align:center;
  background-image:linear-gradient(to right,rgba(248,57,41,0),#f48a00,rgba(248,57,41,0));
}

/* 图片
 * 宽度 width:100%;
 * 居中 margin:0 auto;
 * 居左 margin:0 0;
 */
#article img {
  border-radius:5px 5px 5px 5px;
  display:block;
  margin:0px 10px auto;
  width:100%;
  height:100%;
  object-fit:contain;
  /*box-shadow: #ede0d0 0px 6px 20px;*/
}

/* 图片描述文字 */
#article figcaption {
  display:block;
  font-size:14px;
  margin-top: 10px;
  color:rgba(0,0,0,0.65);
  text-align:center;
}

/* 行内代码 */
#article p code, #article li code {
  	color:#E78E34;
    font-size: 15px;
    word-wrap: break-word;
    padding: 2px 4px;
    border-radius: 3px;
    margin: 0 2px;
    background-color: #fff6ed;
    font-family: Operator Mono, Consolas, Monaco, Menlo, monospace;
    word-break: break-all;
}


/* 非微信代码块
 * 代码块不换行 display:-webkit-box !important;
 * 代码块换行 display:block;
 */
#article pre code {
}

/*
 * 表格内的单元格
 * 字体大小 font-size: 16px;
 * 边框 border: 1px solid #ccc;
 * 内边距 padding: 5px 10px;
 */
#article table tr th,
#article table tr td {
  font-size: 14px;
}

/* 脚注文字 */
#article .footnote-word {
  color:#f48a00;
}

/* 脚注上标 */
#article .footnote-ref {
  color:#f48a00;
}

/*脚注链接样式*/
#article .footnote-item em {
  font-style:normal;
  color:rgba(0,0,0,0.65);
  font-size:13px;
}

/* "参考资料"四个字 
